import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';


const MyBookings = () => {

    const navigate = useNavigate();
    let data;
    let outputArr=[];
    const AuthenticationPage = async () => {
        try {
            const res = await fetch('/getUser', {
                method: "GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                credentials: "include"
            });

            data = await res.json();
            console.log(data);

            if (!res.status === 200) {
                const error = new Error(res.error);
                throw error;
            }
        }
        catch (err) {
            console.log(err);
            navigate('/login');
        }
    }

    const getBookingsPage = async () => {
        try {
        console.log("booking aagye inside try before res");
        
        
        const res=await fetch('/showBookings',{
            method:"GET",
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",

                },
                data
            });
            console.log("booking aagye inside try before output");
            outputArr=await res.json();
            
            console.log("booking aagye inside try before res.status");
            if(!res.status===200)
            {
                const error = new Error(res.error);
                throw error;
            }
            console.log("booking aagye inside try after res.status");
            
            console.log(outputArr);
        }
        catch (err) {
            console.log(err);
            navigate('/login');
        }
    }

    useEffect(() => {
        // AuthenticationPage();
        console.log("booking pe jane walee h");
        getBookingsPage();
    }, []);

    // let {myBookings}=userData;

    return (
        <div className='flex justify-center items-center text-white text-3xl h-screen '>
        {
          outputArr.length===0?<p>No Data</p>:<p>Data found</p>
        }
        </div>
    )
}

export default MyBookings
